mapper.select:
SELECT id, name, short_name, description, logo_url, official_website, is_985, is_211, is_double_first_class, school_type, education_level, tags, province, city, ( SELECT ROUND(AVG(ur.overall_score), 2) FROM university_review ur WHERE ur.university_id = university.id AND ur.is_deleted = 0 ) AS overall_score, ( SELECT COUNT(*) FROM university_review ur WHERE ur.university_id = university.id AND ur.is_deleted = 0 ) AS review_count FROM university
is_deleted = 0
AND (name LIKE CONCAT('%', #{keyword}, '%') OR short_name LIKE CONCAT('%', #{keyword}, '%'))
AND province = #{province}
AND city = #{city}
ORDER BY id
